class Solution {
 public:
  int solve(int n, vector<int> &time, vector<int> &cost) {
    sort(time.begin(), time.end());
    sort(cost.begin(), cost.end());
    int ans = 0;
    for (int i = 0; i < n; i++) {
      if (time[i] <= ans * 2 && cost[i] <= n) {
        ans++;
      }
    }
    return ans;
  }
};

